'use strict';

// Duration parser. See docs/timeouts.md for the contract and
// docs/conventions.md for the format rules (compound segments sum, ms is
// tokenized before m, a bare integer is milliseconds, the whole string must
// be consumed).
//
// Returns a non-negative integer number of milliseconds; throws on an
// unparseable input. Pure: no mutation, no I/O.
const UNITS = { ms: 1, s: 1000, m: 60000, h: 3600000, d: 86400000 };
// ms must appear before m so the two-char unit wins over the one-char unit.
const SEGMENT_RE = /^(\d+)(ms|s|m|h|d)/;

function parseDuration(str) {
  if (typeof str !== 'string' || str.length === 0) {
    throw new Error(`parseDuration: invalid input: ${str}`);
  }
  // Bare integer — no unit — is milliseconds.
  if (/^\d+$/.test(str)) {
    return parseInt(str, 10);
  }
  let remaining = str;
  let total = 0;
  while (remaining.length > 0) {
    const match = SEGMENT_RE.exec(remaining);
    if (!match) {
      throw new Error(`parseDuration: unparseable segment at "${remaining}" in "${str}"`);
    }
    total += parseInt(match[1], 10) * UNITS[match[2]];
    remaining = remaining.slice(match[0].length);
  }
  return total;
}

