const { parseDuration } = require('./src/core/duration.js');
const cases = [
  ['30s', 30000],
  ['1h30m', 5400000],
  ['500ms', 500],
  ['250', 250],
  ['1d', 86400000],
  ['2h30m15s', 9015000],
];
