for (const [input, expected] of cases) {
  const got = parseDuration(input);
  const ok = got === expected;
  if (!ok) pass = false;
  console.log(ok ? 'PASS' : 'FAIL', input, '->', got, ok ? '' : '(expected ' + expected + ')');
