try { parseDuration('abc'); console.log('FAIL abc should throw'); pass = false; } catch { console.log('PASS abc throws'); }
try { parseDuration('1h2x'); console.log('FAIL 1h2x should throw'); pass = false; } catch { console.log('PASS 1h2x throws'); }
console.log(pass ? 'ALL PASS' : 'SOME FAILED');
